==============================================================================
--- head/sys/net/if_gif.c	Wed Mar  2 20:08:52 2011	(r219205)
+++ head/sys/net/if_gif.c	Wed Mar  2 21:39:08 2011	(r219206)
@@ -35,6 +35,7 @@

 #include <sys/param.h>
 #include <sys/systm.h>
